headers = {
    "apikey": SUPABASE_KEY,
    "Authorization": f"Bearer {SUPABASE_KEY}",
    "Content-Type": "application/json",
    "Prefer": "return=minimal",
}

# Build insert records (no embedding for now — use NULL)
records = []
for t in TEMPLATES:
    records.append({
        "title": t["title"],
        "funder_name": t.get("funder_name"),
        "funder_type": t.get("funder_type"),
        "program_name": t.get("program_name"),
        "cfda_number": t.get("cfda_number"),
        "section_key": t["section_key"],
        "section_title": t["section_title"],
        "content_md": t["content_md"],
        "word_count": len(t["content_md"].split()),
        "typical_word_limit": t.get("typical_word_limit", 600),
        "org_types": t.get("org_types", []),
        "program_types": t.get("program_types", []),
        "tags": t.get("tags", []),
        "win_count": t.get("win_count", 0),
        "use_count": t.get("use_count", 0),
        "is_public": True,
    })

# Insert in batches of 10
batch_size = 10
inserted = 0
for i in range(0, len(records), batch_size):
    batch = records[i:i+batch_size]
    data = json.dumps(batch).encode()
    req = urllib.request.Request(
        f"{SUPABASE_URL}/rest/v1/templates",
        data=data,
        headers=headers,
        method="POST",
    )
    try:
        with urllib.request.urlopen(req) as resp:
            inserted += len(batch)
            print(f"Inserted batch {i//batch_size + 1}: {len(batch)} records (total: {inserted})")
    except urllib.error.HTTPError as e:
        print(f"Error batch {i//batch_size + 1}: {e.code} {e.read().decode()}")

print(f"\nDone. {inserted} templates inserted.")
